"use client"
import Link from "next/link";

import { usePathname } from "next/navigation";

type Props = {
  navState: "transparent" | "gradient" | "white"
}

const changeLanguage = (lang:String) => {
  console.log("Change language to:", lang);
  // ici tu connecteras ton système i18n plus tard
};

export default function Navbar({navState}:Props) {
  const pathname = usePathname();
  const linkClass = (path: string) =>
    `transition ${
      pathname === path
        ? "text-white-600 font-semibold border-b-1 border-blue-100"
        : "hover:text-blue-100"
    }`;

  return (
    <header
       className={`fixed top-0 w-full z-50 transition-all duration-300 py-4

      ${navState === "transparent" && "bg-transparent"}

      ${navState === "gradient" && "bg-gradient-to-r from-[#d7e8f2] via-[#a9c9e4] to-[#6fa6d8] shadow-lg backdrop-blur-md"}

      ${navState === "white" && "bg-white shadow-md"}
      `}
    >

      <div className="max-w-7xl mx-auto flex items-center justify-between px-10">

        {/* Logo */}
        <div className="text-xl font-semibold text-slate-800">
          SOHBLITZ Mobil
        </div>

       {/* Menu */}
        <nav className="hidden md:flex gap-8 text-slate-700">

        <Link href="/" className={linkClass("/")}>
            Home
        </Link>

        <Link href="/about" className={linkClass("/about")}>
            Über Uns
        </Link>

        <Link href="/services" className={linkClass("/services")}>
            Dienste
        </Link>

        <Link href="/impressum" className={linkClass("/impressum")}>
            Impressum
        </Link>

        <Link href="/privacy" className={linkClass("/privacy")}>
            Datenschutz
        </Link>

        <Link href="/contact" className={linkClass("/contact")}>
            Kontakt
        </Link>
        </nav>
        
        {/* Language Switcher */}
      <div className="flex gap-4 items-center text-xl">

        <button
          onClick={() => changeLanguage("de")}
          className="hover:scale-110 transition"
          aria-label="Deutsch"
        >
          🇩🇪
        </button>

        <button
          onClick={() => changeLanguage("en")}
          className="hover:scale-110 transition"
          aria-label="English"
        >
          🇬🇧
        </button>

      </div>

      </div>

    </header>
  )
}